-- コテージ モバイル表示コンテンツ (cottage_content) の作成 + 初期 seed。
--
-- 背景: cottage-ios アプリが表示する「タイムテーブル以外の全コンテンツ」
--   (旅行概要 / 催し / レシピ / 持ち物 / 班 / 集金 / 版一覧 / 会場マップ) は
--   これまでアプリ内 SampleData.swift にハードコードされていた。これを
--   バックエンド駆動にし、管理画面から全項目を編集できるようにする。
--
-- 設計: timetable と同じ「1 ドキュメント = 1 行」方式。id 固定値 'cottage'、
--   data 列に全セクションを JSON で保持する。公開 GET /api/cottage/content が
--   配信し、admin PUT /api/cottage/content が上書きする。
--
-- 後方互換: 新規テーブルの追加のみ。既存テーブルには一切触れない。
--   seed は INSERT OR IGNORE なので再適用しても既存行を壊さない。
--   seed 内容は cottage-ios SampleData.swift と verbatim で整合させている。

CREATE TABLE `cottage_content` (
	`id` text PRIMARY KEY NOT NULL,
	`data` text NOT NULL,
	`updated_at` text NOT NULL
);
--> statement-breakpoint
INSERT OR IGNORE INTO `cottage_content` (`id`, `data`, `updated_at`) VALUES ('cottage', '{"trip":{"title":"瀬女コテージ村 旅行","location":"瀬女コテージ村（石川県白山市）","startDate":"2026-08-06","endDate":"2026-08-07","nights":1,"participantCount":13,"notes":["1泊2日。確定参加13名（男性9・女性4）＋参加未定6名。","スイカ割り・川釣り・BBQ・宝探し・天体観測。雨天時は人狼。","[要データ] 車・運転手・班割りは8/5までに確定予定。","[要データ] 集金額は集計中。"]},"activities":[{"id":"watermelon","name":"スイカ割り","emoji":"🍉","summary":"広場で定番のスイカ割り。冷やして食べる。","description":"広場でスイカ割り。氷水でスイカを冷やし、割った後はみんなで食べます。費用目安は合計6,300〜8,500円。","location":"瀬女コテージ村 広場","tips":["スイカ","割る棒（1,500円）","タライ・氷水","ブルーシート","目隠しタオル","包丁とまな板"]},{"id":"fishing","name":"川釣り","emoji":"🎣","summary":"吉野観光の管理釣り場で川釣り体験。","description":"管理釣り場で川釣り。営業〜18:00、コテージから車15分。初心者でも釣りやすい。","location":"吉野観光 管理釣り場（車15分）","tips":["濡れてもよい服・サンダル","タオル","料金/竿レンタルは現地確認"]},{"id":"bbq","name":"BBQ","emoji":"🍖","summary":"コテージでBBQ。食材費は別途集金。","description":"BBQ設備で夕食。BBQセット計8,000円、食材2,200円/人を別途集金。火起こし・配膳は班で分担。","location":"瀬女コテージ村 BBQ場","tips":["食材費2,200円/人","BBQセット","紙皿・紙コップ","軍手・トング・着火剤","ゴミ袋"]},{"id":"treasure","name":"宝探し","emoji":"🔦","summary":"夜の広場で宝探し。怖がらせ演出を仕込む。","description":"BBQ片付け後、夜の広場で宝探し。男女が別れるタイミングでドッキリ演出を予定。","location":"瀬女コテージ村 広場・周辺","tips":["懐中電灯","進行役・仕掛け役を決める","羽織るもの"]},{"id":"stargazing","name":"天体観測","emoji":"🔭","summary":"ブルーシートで星空観賞。","description":"宝探しのあと、ブルーシートを敷いて星空観賞。アイス片手にまったり。","location":"瀬女コテージ村 周辺","tips":["ブルーシート","アイス","羽織るもの","虫よけ"]}],"recipes":[{"id":"frenchtoast","name":"ふわとろフレンチトースト","emoji":"🍞","category":"朝食","servings":"4人分","time":"約20分（漬け込み込み）","ingredients":["食パン（4枚切り）4枚 ※厚切りほどふわとろ","卵 3個","牛乳 200ml","砂糖 大さじ3","バター 20g","お好みで：はちみつ・メープル・粉砂糖"],"steps":["卵・牛乳・砂糖をボウルでよく混ぜ、卵液を作る。","食パンを半分に切り、卵液に浸す（両面・各5分）。急ぐなら電子レンジ500W30秒で染み込みが早まる。","フライパンを弱めの中火で熱し、バターを溶かす。","パンを並べ、フタをして片面3〜4分。焼き色がついたら裏返す。","裏面も2〜3分、フタをして中までふんわり火を通す。","皿に盛り、はちみつや粉砂糖をかけて完成。"],"tips":["弱火＋フタが「ふわとろ」の最大のコツ。強火は表面だけ焦げる。","前夜に卵液へ漬けて冷やしておくと朝は焼くだけで時短。","コテージのコンロが強いときはバターが焦げやすいので火加減に注意。"]},{"id":"bbq","name":"炭火BBQ 火起こし＆焼き方のコツ","emoji":"🔥","category":"BBQ","servings":"13人前後","time":"火起こし約30分","ingredients":["炭（1人あたり300〜400gが目安）","着火剤・チャッカマン","うちわ または 火吹き棒","トング（生肉用と盛り付け用で分ける）","軍手・アルミホイル"],"steps":["炭をコンロの中央に山積みにし、すき間に着火剤を差し込む。","着火剤に点火し、炭が組み崩れないよう10〜15分そのまま待つ。","炭の表面が白い灰をかぶったら火が安定した合図。トングで全体に広げる。","片側を炭多め（強火）、片側を少なめ（弱火）にして火力ゾーンを作る。","強火で肉に焼き色をつけ、弱火ゾーンでじっくり火を通す。","野菜は弱火ゾーンでゆっくり。焦げそうなものはホイルに包む。"],"tips":["炭は最初に多めに熾すと後がラク。途中の継ぎ足しは中央へ。","生肉を触ったトングで焼けた肉を触らない（食中毒予防）。","火が消えそうなら火吹き棒で根元に空気を送る。うちわでも可。"]},{"id":"foilbake","name":"鮭ときのこのホイル焼き","emoji":"🐟","category":"BBQの副菜","servings":"4人分","time":"約20分","ingredients":["生鮭 4切れ","しめじ・えのき 各1パック","玉ねぎ 1個（薄切り）","バター 4かけ","塩こしょう・しょうゆ 少々","アルミホイル（厚手）"],"steps":["ホイルを大きめに切り、玉ねぎ→鮭→きのこの順にのせる。","塩こしょうを振り、バター1かけとしょうゆを少々たらす。","ホイルの口をしっかり閉じ、汁がもれない包みを作る。","BBQの弱火ゾーン（網の端）に置き、フタや別ホイルをかぶせて10〜12分。","きのこがしんなり・鮭に火が通れば完成。やけどに注意して開ける。"],"tips":["ホイルは二重にすると破れにくく汁もれしにくい。","BBQの炭が落ち着いた後半に置くと焦がさず作れる。","鮭の代わりに鶏もも・ホタテでも同じ手順でおいしい。"]},{"id":"peperoncino","name":"〆のガーリックペペロンチーノ","emoji":"🍝","category":"夜食・締め","servings":"4人分","time":"約15分","ingredients":["パスタ 320g","にんにく 3かけ（みじん切り）","鷹の爪 1〜2本（輪切り）","オリーブオイル 大さじ4","塩（ゆで用）・黒こしょう","お好みでベーコンやキャベツ"],"steps":["大きめの鍋に湯を沸かし、塩を入れてパスタを表示時間どおりゆでる。","フライパンに弱火でオイル・にんにく・鷹の爪を入れ、香りを出す（焦がさない）。","ゆで汁をお玉1杯加え、オイルと混ぜて乳化させる（とろみが出る）。","ゆで上げたパスタを加え、手早く全体をあえる。","塩・黒こしょうで味を調えて完成。"],"tips":["にんにくは弱火でじっくり。焦がすと苦くなる。","ゆで汁を加えて乳化させると、オイルが麺によくからむ。","BBQで余ったベーコン・野菜を入れると一気にごちそうに。"]},{"id":"smore","name":"焼きマシュマロ＆スモア","emoji":"🍫","category":"夜食・レク","servings":"みんなで","time":"約5分","ingredients":["マシュマロ 1袋","ビスケット（クラッカー）適量","板チョコ 1〜2枚","長めの串 または 竹串"],"steps":["BBQの残り火（弱火）でマシュマロを串に刺してあぶる。","表面がきつね色にとろけたら火から外す。","ビスケットに板チョコをのせ、その上に焼きマシュマロをのせる。","もう1枚のビスケットではさみ、軽く押して完成（スモア）。"],"tips":["強火で炙ると一瞬で焦げる。残り火でゆっくりが◎。","チョコはマシュマロの熱でほどよく溶ける。","火のそばは大人がつき添い、串の扱いに注意。"]}],"packing":[{"id":"p1","label":"着替え（1泊分）","category":"基本"},{"id":"p2","label":"タオル（数枚）","category":"基本"},{"id":"p3","label":"洗面用具・歯ブラシ","category":"基本"},{"id":"p4","label":"健康保険証・常備薬","category":"基本"},{"id":"p5","label":"モバイルバッ